customCss:
/* Terminal theme: CRT scanlines + glow */
body {
  text-shadow: 0 0 2px currentColor;
}

/* Scanline overlay */
body::before {
  content: "";
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 9998;
  background: repeating-linear-gradient(
    0deg,
    rgba(0, 0, 0, 0) 0px,
    rgba(0, 0, 0, 0) 2px,
    rgba(0, 0, 0, 0.15) 3px,
    rgba(0, 0, 0, 0.15) 4px
  );
}

/* Flicker effect */
@keyframes flicker {
  0%, 100% { opacity: 1; }
  98% { opacity: 1; }
  99% { opacity: 0.85; }
}

body {
  animation: flicker 6s infinite;
}

/* Pixelated rendering for images */
img {
  image-rendering: pixelated;
}
